UPDATE `blog_topic_article` SET `deleted_at`='2026-05-08 23:39:49',`updated_at`='2026-05-08 23:39:49' WHERE `topic_id` IN (9306001, 9306002, 9306003);


UPDATE `blog_tag` t SET `use_count` = (SELECT COUNT(*) FROM `blog_article_tag` atg WHERE atg.`tag_name` = t.`name` AND atg.`deleted_at` IS NULL) WHERE t.`name` IN ('JVM', 'ORM框架 - MyBatis知识体系详解', 'Web容器 - Tomcat知识体系详解', '分表分库 - ShardingSphere详解', '并发编程', '架构设计', '框架', '源码解析', '线程池');

UPDATE `blog_column` c SET `article_count` = (SELECT COUNT(*) FROM `blog_column_article` ca INNER JOIN `blog_article` a ON a.`id` = ca.`article_id` WHERE ca.`column_id` = c.`id` AND ca.`deleted_at` IS NULL AND a.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED') WHERE c.`id` IN (9200006);

UPDATE `blog_topic` t SET `article_count` = (SELECT COUNT(*) FROM `blog_topic_article` ta INNER JOIN `blog_article` a ON a.`id` = ta.`article_id` WHERE ta.`topic_id` = t.`id` AND ta.`deleted_at` IS NULL AND a.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED') WHERE t.`id` IN (9306001, 9306002, 9306003);

